using System;
using System.Collections.Generic;
using System.Collections.ObjectModel;
using System.Linq;
using System.Text.Json;
using System.Windows;
using System.Windows.Controls;
using WeldMonitorV2.Data;
using WeldMonitorV2.Models;

namespace WeldMonitorV2;

/// <summary>
/// Helper class for JIG ComboBox display.
/// </summary>
public class JigComboItem
{
    public JigInfo Jig { get; set; } = null!;
    public string DisplayText => $"[{Jig.JigId}] {Jig.PartName}";
}

/// <summary>
/// Sequence (Point spec) management window.
/// </summary>
public partial class SeqWindow : Window
{
    private readonly JigRepository _repo;
    private ObservableCollection<PointSpec> _points = new();
    private JigInfo? _selectedJig;

    public SeqWindow(JigRepository repo)
    {
        InitializeComponent();
        _repo = repo;
        LoadJigCombo();
    }

    private void LoadJigCombo()
    {
        // Show JIGs that have PartNo or Points
        var all = _repo.All
            .Where(j => !string.IsNullOrEmpty(j.PartNo) || j.Points.Count > 0)
            .Select(j => new JigComboItem { Jig = j })
            .ToList();

        JigComboBox.ItemsSource = all;
        if (all.Count > 0)
            JigComboBox.SelectedIndex = 0;
    }

    private void OnJigSelectionChanged(object sender, SelectionChangedEventArgs e)
    {
        if (JigComboBox.SelectedItem is not JigComboItem item) return;

        _selectedJig = item.Jig;
        LoadPoints(_selectedJig);
        LoadJigSettings(_selectedJig);
        JigInfoText.Text = $"JIG {_selectedJig.JigId} | {_selectedJig.PartNo} | Points: {_points.Count}";
    }

    private void LoadPoints(JigInfo jig)
    {
        // Deep-copy points to allow editing without affecting original until Apply
        _points = new ObservableCollection<PointSpec>(
            jig.Points.Select(DeepCopyPoint));

        // Ensure PointId is sequential
        for (int i = 0; i < _points.Count; i++)
            _points[i] = _points[i] with { PointId = i + 1 };

        SeqDataGrid.ItemsSource = _points;
    }

    private void OnAdd(object sender, RoutedEventArgs e)
    {
        var newPoint = new PointSpec
        {
            PointId = _points.Count + 1,
            Amp = new MeasureSpec { Min = 0, Max = 0, Tol = 1.0, Type = "평균" },
            Volt = new MeasureSpec { Min = 0, Max = 0, Tol = 1.0, Type = "평균" },
            Flow = new MeasureSpec { Min = 0, Max = 0, Tol = 1.0, Type = "평균" },
            Pass = false
        };
        _points.Add(newPoint);
        UpdatePointIds();
    }

    private void OnDelete(object sender, RoutedEventArgs e)
    {
        if (SeqDataGrid.SelectedItem is not PointSpec selected) return;
        _points.Remove(selected);
        UpdatePointIds();
    }

    private void OnCopy(object sender, RoutedEventArgs e)
    {
        if (_selectedJig == null || _points.Count == 0)
        {
            MessageBox.Show("복사할 포인트가 없습니다.", "경고",
                MessageBoxButton.OK, MessageBoxImage.Warning);
            return;
        }

        // Show JIG selection dialog
        var targets = _repo.GetRegistered()
            .Where(j => j.JigId != _selectedJig.JigId)
            .ToList();

        if (targets.Count == 0)
        {
            MessageBox.Show("복사할 대상 JIG가 없습니다.", "경고",
                MessageBoxButton.OK, MessageBoxImage.Warning);
            return;
        }

        var dlg = new CopyTargetDialog(targets) { Owner = this };
        if (dlg.ShowDialog() != true || dlg.SelectedJig == null) return;

        var targetJig = dlg.SelectedJig;
        targetJig.Points = _points.Select(DeepCopyPoint).ToList();
        targetJig.StartSector = _selectedJig.StartSector;
        targetJig.EndSector = _selectedJig.EndSector;
        targetJig.GraphWidth = _selectedJig.GraphWidth;
        _repo.AddOrUpdate(targetJig);
        _repo.Save();

        JigInfoText.Text = $"JIG {_selectedJig.JigId} → JIG {targetJig.JigId} 복사 완료 ({_points.Count}개 포인트)";
    }

    private void OnApplyToJig(object sender, RoutedEventArgs e)
    {
        if (_selectedJig == null)
        {
            MessageBox.Show("먼저 JIG를 선택하세요.", "경고",
                MessageBoxButton.OK, MessageBoxImage.Warning);
            return;
        }

        if (SeqDataGrid.SelectedItem is not PointSpec selected)
        {
            MessageBox.Show("적용할 행을 선택하세요.", "경고",
                MessageBoxButton.OK, MessageBoxImage.Warning);
            return;
        }

        var result = MessageBox.Show(
            $"선택한 행의 설정을 이 JIG의 모든 포인트({_points.Count}개)에 동일하게 적용하시겠습니까?",
            "JIG 적용", MessageBoxButton.YesNo, MessageBoxImage.Question);
        if (result != MessageBoxResult.Yes) return;

        // Apply selected row's spec to all points in this JIG
        for (int i = 0; i < _points.Count; i++)
        {
            _points[i] = _points[i] with
            {
                Amp = new MeasureSpec { Min = selected.Amp.Min, Max = selected.Amp.Max, Tol = selected.Amp.Tol, Type = selected.Amp.Type },
                Volt = new MeasureSpec { Min = selected.Volt.Min, Max = selected.Volt.Max, Tol = selected.Volt.Tol, Type = selected.Volt.Type },
                Flow = new MeasureSpec { Min = selected.Flow.Min, Max = selected.Flow.Max, Tol = selected.Flow.Tol, Type = selected.Flow.Type },
                Pass = selected.Pass
            };
        }

        SeqDataGrid.ItemsSource = null;
        SeqDataGrid.ItemsSource = _points;
        JigInfoText.Text = $"JIG {_selectedJig.JigId} | 전체 {_points.Count}개 포인트에 적용 완료";
    }

    private void OnApplyToAll(object sender, RoutedEventArgs e)
    {
        if (SeqDataGrid.SelectedItem is not PointSpec selected)
        {
            MessageBox.Show("적용할 행을 선택하세요.", "경고",
                MessageBoxButton.OK, MessageBoxImage.Warning);
            return;
        }

        var result = MessageBox.Show(
            "선택한 행의 설정을 모든 등록된 JIG의 모든 포인트에 적용하시겠습니까?\n기존 설정이 덮어씌워집니다.",
            "전체 적용", MessageBoxButton.YesNo, MessageBoxImage.Warning);
        if (result != MessageBoxResult.Yes) return;

        var registered = _repo.GetRegistered();
        int jigCount = 0;
        foreach (var jig in registered)
        {
            for (int i = 0; i < jig.Points.Count; i++)
            {
                jig.Points[i] = jig.Points[i] with
                {
                    Amp = new MeasureSpec { Min = selected.Amp.Min, Max = selected.Amp.Max, Tol = selected.Amp.Tol, Type = selected.Amp.Type },
                    Volt = new MeasureSpec { Min = selected.Volt.Min, Max = selected.Volt.Max, Tol = selected.Volt.Tol, Type = selected.Volt.Type },
                    Flow = new MeasureSpec { Min = selected.Flow.Min, Max = selected.Flow.Max, Tol = selected.Flow.Tol, Type = selected.Flow.Type },
                    Pass = selected.Pass
                };
            }
            _repo.AddOrUpdate(jig);
            jigCount++;
        }

        _repo.Save();

        // Refresh current view
        if (_selectedJig != null) LoadPoints(_selectedJig);
        JigInfoText.Text = $"전체 {jigCount}개 JIG에 적용 완료";
    }

    private void OnSave(object sender, RoutedEventArgs e)
    {
        try
        {
            // Apply current points to selected JIG before saving
            if (_selectedJig != null)
            {
                SaveJigSettings(_selectedJig);
                _selectedJig.Points = _points.Select(DeepCopyPoint).ToList();
                _repo.AddOrUpdate(_selectedJig);
            }

            _repo.Save();
            MessageBox.Show("시퀀스 데이터가 저장되었습니다.", "저장",
                MessageBoxButton.OK, MessageBoxImage.Information);
        }
        catch (Exception ex)
        {
            MessageBox.Show($"저장 실패: {ex.Message}", "오류",
                MessageBoxButton.OK, MessageBoxImage.Error);
        }
    }

    private void LoadJigSettings(JigInfo jig)
    {
        txtStartSector.Text = jig.StartSector.ToString("0.##");
        txtEndSector.Text = jig.EndSector.ToString("0.##");
        txtGraphWidth.Text = jig.GraphWidth.ToString("0.##");
    }

    private void SaveJigSettings(JigInfo jig)
    {
        jig.StartSector = double.TryParse(txtStartSector.Text, out var ss) ? ss : 5;
        jig.EndSector = double.TryParse(txtEndSector.Text, out var es) ? es : 95;
        jig.GraphWidth = double.TryParse(txtGraphWidth.Text, out var gw) ? gw : 5;
    }

    private void OnClose(object sender, RoutedEventArgs e)
    {
        Close();
    }

    private void UpdatePointIds()
    {
        for (int i = 0; i < _points.Count; i++)
            _points[i] = _points[i] with { PointId = i + 1 };

        SeqDataGrid.ItemsSource = null;
        SeqDataGrid.ItemsSource = _points;
    }

    private static PointSpec DeepCopyPoint(PointSpec src)
    {
        return src with
        {
            Amp = new MeasureSpec { Min = src.Amp.Min, Max = src.Amp.Max, Tol = src.Amp.Tol, Type = src.Amp.Type },
            Volt = new MeasureSpec { Min = src.Volt.Min, Max = src.Volt.Max, Tol = src.Volt.Tol, Type = src.Volt.Type },
            Flow = new MeasureSpec { Min = src.Flow.Min, Max = src.Flow.Max, Tol = src.Flow.Tol, Type = src.Flow.Type },
            Image = new ImageCoord { X = src.Image.X, Y = src.Image.Y, W = src.Image.W, H = src.Image.H }
        };
    }
}

