using System;
using System.Collections.Generic;
using System.Collections.ObjectModel;
using System.IO;
using System.Linq;
using System.Windows;
using System.Windows.Controls;
using System.Windows.Input;
using System.Windows.Media;
using System.Windows.Media.Imaging;
using System.Windows.Shapes;
using Microsoft.Win32;
using WeldMonitorV2.Data;
using WeldMonitorV2.Models;

namespace WeldMonitorV2;

/// <summary>
/// View-model row for point coordinate editing in DataGrid.
/// </summary>
public class PointCoordRow
{
    public int PointId { get; set; }
    public double PosX { get; set; }
    public double PosY { get; set; }
    public double SizeX { get; set; }
    public double SizeY { get; set; }
}

/// <summary>
/// Image coordinate setup window. Allows placing weld point markers on a JIG image.
/// </summary>
public partial class ImageSetWindow : Window
{
    private const double DEFAULT_SIZE = 10;
    private const double MIN_SIZE = 4;
    private const double MAX_SIZE = 60;
    private const double WHEEL_STEP = 2;

    private readonly JigRepository _jigRepo;
    private JigInfo? _selectedJig;
    private string _currentImagePath = "";
    private BitmapImage? _loadedImage;
    private Image? _canvasImage;

    private readonly ObservableCollection<PointCoordRow> _pointRows = new();
    private int _selectedPointIndex = -1;

    // Drag state
    private bool _isDragging;
    private int _dragPointIndex = -1;
    private Point _dragOffset;

    public ImageSetWindow(JigRepository jigRepo)
    {
        InitializeComponent();
        _jigRepo = jigRepo;
        PointsDataGrid.ItemsSource = _pointRows;
        LoadJigComboBox();
    }

    // --- Initialization ---

    private void LoadJigComboBox()
    {
        var enabled = _jigRepo.GetRegistered();
        JigComboBox.ItemsSource = enabled;
        if (enabled.Count > 0)
            JigComboBox.SelectedIndex = 0;
    }

    // --- JIG selection ---

    private void JigComboBox_SelectionChanged(object sender, SelectionChangedEventArgs e)
    {
        if (JigComboBox.SelectedItem is not JigInfo jig) return;
        _selectedJig = jig;
        _currentImagePath = jig.ImagePath ?? "";
        LoadImageToCanvas();
        LoadPointRows();
        RedrawMarkers();
    }

    // --- Image loading ---

    private void LoadImageButton_Click(object sender, RoutedEventArgs e)
    {
        var dlg = new OpenFileDialog
        {
            Filter = "Image files|*.png;*.jpg;*.jpeg;*.bmp|All files|*.*"
        };
        if (dlg.ShowDialog() != true) return;

        _currentImagePath = dlg.FileName;
        LoadImageToCanvas();
        RedrawMarkers();
    }

    private void LoadImageToCanvas()
    {
        ImageCanvas.Children.Clear();
        _canvasImage = null;
        _loadedImage = null;

        if (string.IsNullOrEmpty(_currentImagePath) || !File.Exists(_currentImagePath))
            return;

        try
        {
            var bmp = new BitmapImage();
            bmp.BeginInit();
            bmp.UriSource = new Uri(_currentImagePath, UriKind.Absolute);
            bmp.CacheOption = BitmapCacheOption.OnLoad;
            bmp.EndInit();
            _loadedImage = bmp;

            _canvasImage = new Image
            {
                Source = bmp,
                Stretch = Stretch.Uniform
            };
            ImageCanvas.Children.Add(_canvasImage);
            LayoutCanvasImage();
        }
        catch { /* ignore invalid image */ }
    }

    private void ImageCanvas_SizeChanged(object sender, SizeChangedEventArgs e)
    {
        LayoutCanvasImage();
        RedrawMarkers();
    }

    private void LayoutCanvasImage()
    {
        if (_canvasImage == null || _loadedImage == null) return;

        double cw = ImageCanvas.ActualWidth;
        double ch = ImageCanvas.ActualHeight;
        if (cw <= 0 || ch <= 0) return;

        double iw = _loadedImage.PixelWidth;
        double ih = _loadedImage.PixelHeight;
        double scale = Math.Min(cw / iw, ch / ih);

        _canvasImage.Width = iw * scale;
        _canvasImage.Height = ih * scale;
        Canvas.SetLeft(_canvasImage, (cw - _canvasImage.Width) / 2);
        Canvas.SetTop(_canvasImage, (ch - _canvasImage.Height) / 2);
    }

    // --- Point data ---

    private void LoadPointRows()
    {
        _pointRows.Clear();
        if (_selectedJig == null) return;

        foreach (var pt in _selectedJig.Points)
        {
            _pointRows.Add(new PointCoordRow
            {
                PointId = pt.PointId,
                PosX = pt.Image.X,
                PosY = pt.Image.Y,
                SizeX = pt.Image.W,
                SizeY = pt.Image.H
            });
        }
    }

    private void AddPointButton_Click(object sender, RoutedEventArgs e)
    {
        if (_selectedJig == null) return;

        int nextId = _pointRows.Count > 0
            ? _pointRows.Max(r => r.PointId) + 1
            : 1;

        _pointRows.Add(new PointCoordRow
        {
            PointId = nextId,
            PosX = 50, PosY = 50,
            SizeX = DEFAULT_SIZE, SizeY = DEFAULT_SIZE
        });
        RedrawMarkers();
    }

    // --- DataGrid events ---

    private void PointsDataGrid_SelectionChanged(object sender, SelectionChangedEventArgs e)
    {
        _selectedPointIndex = PointsDataGrid.SelectedIndex;
        RedrawMarkers();
    }

    private void PointsDataGrid_CellEditEnding(object sender, DataGridCellEditEndingEventArgs e)
    {
        // Redraw after edit completes
        Dispatcher.BeginInvoke(new Action(RedrawMarkers),
            System.Windows.Threading.DispatcherPriority.Background);
    }

    // --- Canvas interaction ---

    private void ImageCanvas_MouseLeftButtonDown(object sender, MouseButtonEventArgs e)
    {
        var pos = e.GetPosition(ImageCanvas);

        // Check if clicking on an existing marker
        int hitIndex = HitTestMarker(pos);
        if (hitIndex >= 0)
        {
            _isDragging = true;
            _dragPointIndex = hitIndex;
            var row = _pointRows[hitIndex];
            var canvasPos = ImageToCanvas(row.PosX, row.PosY);
            _dragOffset = new Point(pos.X - canvasPos.X, pos.Y - canvasPos.Y);
            ImageCanvas.CaptureMouse();
            PointsDataGrid.SelectedIndex = hitIndex;
            return;
        }

        // Click sets position for selected point
        if (_selectedPointIndex >= 0 && _selectedPointIndex < _pointRows.Count)
        {
            var imgPos = CanvasToImage(pos.X, pos.Y);
            _pointRows[_selectedPointIndex].PosX = Math.Round(imgPos.X, 1);
            _pointRows[_selectedPointIndex].PosY = Math.Round(imgPos.Y, 1);
            PointsDataGrid.Items.Refresh();
            RedrawMarkers();
        }
    }

    private void ImageCanvas_MouseMove(object sender, MouseEventArgs e)
    {
        if (!_isDragging || _dragPointIndex < 0) return;

        var pos = e.GetPosition(ImageCanvas);
        var imgPos = CanvasToImage(pos.X - _dragOffset.X, pos.Y - _dragOffset.Y);
        _pointRows[_dragPointIndex].PosX = Math.Round(imgPos.X, 1);
        _pointRows[_dragPointIndex].PosY = Math.Round(imgPos.Y, 1);
        PointsDataGrid.Items.Refresh();
        RedrawMarkers();
    }

    private void ImageCanvas_MouseLeftButtonUp(object sender, MouseButtonEventArgs e)
    {
        if (_isDragging)
        {
            _isDragging = false;
            _dragPointIndex = -1;
            ImageCanvas.ReleaseMouseCapture();
        }
    }

    private void ImageCanvas_MouseWheel(object sender, MouseWheelEventArgs e)
    {
        if (_selectedPointIndex < 0 || _selectedPointIndex >= _pointRows.Count) return;

        var row = _pointRows[_selectedPointIndex];
        double delta = e.Delta > 0 ? WHEEL_STEP : -WHEEL_STEP;
        double newSize = Math.Clamp(row.SizeX + delta, MIN_SIZE, MAX_SIZE);

        row.SizeX = newSize;
        row.SizeY = newSize;
        PointsDataGrid.Items.Refresh();
        RedrawMarkers();
        e.Handled = true;
    }

    // --- Coordinate conversion ---

    private Point ImageToCanvas(double ix, double iy)
    {
        if (_canvasImage == null || _loadedImage == null)
            return new Point(ix, iy);

        double scale = _canvasImage.Width / _loadedImage.PixelWidth;
        double offX = Canvas.GetLeft(_canvasImage);
        double offY = Canvas.GetTop(_canvasImage);
        return new Point(ix * scale + offX, iy * scale + offY);
    }

    private Point CanvasToImage(double cx, double cy)
    {
        if (_canvasImage == null || _loadedImage == null)
            return new Point(cx, cy);

        double scale = _canvasImage.Width / _loadedImage.PixelWidth;
        double offX = Canvas.GetLeft(_canvasImage);
        double offY = Canvas.GetTop(_canvasImage);
        return new Point((cx - offX) / scale, (cy - offY) / scale);
    }

    private int HitTestMarker(Point canvasPos)
    {
        for (int i = _pointRows.Count - 1; i >= 0; i--)
        {
            var cpt = ImageToCanvas(_pointRows[i].PosX, _pointRows[i].PosY);
            double dx = canvasPos.X - cpt.X;
            double dy = canvasPos.Y - cpt.Y;
            double r = Math.Max(_pointRows[i].SizeX, MIN_SIZE);
            if (dx * dx + dy * dy <= r * r * 2)
                return i;
        }
        return -1;
    }

    // --- Marker drawing ---

    private void RedrawMarkers()
    {
        // Remove all markers (keep image)
        for (int i = ImageCanvas.Children.Count - 1; i >= 0; i--)
        {
            if (ImageCanvas.Children[i] is not Image)
                ImageCanvas.Children.RemoveAt(i);
        }

        for (int i = 0; i < _pointRows.Count; i++)
        {
            var row = _pointRows[i];
            var cpt = ImageToCanvas(row.PosX, row.PosY);

            Brush fill;
            if (i == _selectedPointIndex)
                fill = Brushes.Gold;
            else if (row.PosX > 0 && row.PosY > 0)
                fill = Brushes.LimeGreen;
            else
                fill = Brushes.Gray;

            // Circle marker — size from row data
            double radius = Math.Max(row.SizeX, MIN_SIZE);
            var circle = new Ellipse
            {
                Width = radius * 2,
                Height = radius * 2,
                Fill = fill,
                Opacity = 0.8,
                IsHitTestVisible = false
            };
            Canvas.SetLeft(circle, cpt.X - radius);
            Canvas.SetTop(circle, cpt.Y - radius);
            ImageCanvas.Children.Add(circle);

            // Point number text — font scales with marker size
            double fontSize = Math.Max(radius * 0.8, 6);
            var txt = new TextBlock
            {
                Text = row.PointId.ToString(),
                Foreground = Brushes.Black,
                FontSize = fontSize,
                FontWeight = FontWeights.Bold,
                IsHitTestVisible = false
            };
            // Center text in circle
            txt.Measure(new Size(double.PositiveInfinity, double.PositiveInfinity));
            double tw = txt.DesiredSize.Width;
            double th = txt.DesiredSize.Height;
            Canvas.SetLeft(txt, cpt.X - tw / 2);
            Canvas.SetTop(txt, cpt.Y - th / 2);
            ImageCanvas.Children.Add(txt);
        }
    }

    private void ApplySizeToAll_Click(object sender, RoutedEventArgs e)
    {
        if (_selectedPointIndex < 0 || _selectedPointIndex >= _pointRows.Count)
        {
            MessageBox.Show("포인트를 먼저 선택하세요.", "경고",
                MessageBoxButton.OK, MessageBoxImage.Warning);
            return;
        }

        var src = _pointRows[_selectedPointIndex];
        foreach (var row in _pointRows)
        {
            row.SizeX = src.SizeX;
            row.SizeY = src.SizeY;
        }

        PointsDataGrid.Items.Refresh();
        RedrawMarkers();
    }

    // --- Save / Close ---

    private void SaveButton_Click(object sender, RoutedEventArgs e)
    {
        if (_selectedJig == null) return;

        _selectedJig.ImagePath = _currentImagePath;

        // Sync points: update existing Image coords, add new points if needed
        while (_selectedJig.Points.Count < _pointRows.Count)
        {
            _selectedJig.Points.Add(new PointSpec
            {
                PointId = _pointRows[_selectedJig.Points.Count].PointId
            });
        }

        for (int i = 0; i < _pointRows.Count; i++)
        {
            var row = _pointRows[i];
            _selectedJig.Points[i].Image = new ImageCoord
            {
                X = row.PosX,
                Y = row.PosY,
                W = row.SizeX,
                H = row.SizeY
            };
        }

        _jigRepo.Save();
