namespace WeldMonitorV2;

/// <summary>
/// Dialog for selecting a target JIG for copy operation.
/// </summary>
public partial class CopyTargetDialog : Window
{
    public JigInfo? SelectedJig { get; private set; }

    public CopyTargetDialog(List<JigInfo> jigs)
    {
        InitializeComponent();

        JigListBox.ItemsSource = jigs.ConvertAll(j => new JigComboItem { Jig = j });
        JigListBox.DisplayMemberPath = "DisplayText";

        if (jigs.Count > 0)
            JigListBox.SelectedIndex = 0;
    }

    private void OnConfirm(object sender, RoutedEventArgs e)
    {
        if (JigListBox.SelectedItem is JigComboItem item)
        {
            SelectedJig = item.Jig;
            DialogResult = true;
        }
    }

    private void OnCancel(object sender, RoutedEventArgs e) => DialogResult = false;

    private void OnDoubleClick(object sender, MouseButtonEventArgs e)
    {
        if (JigListBox.SelectedItem is JigComboItem item)
        {
            SelectedJig = item.Jig;
            DialogResult = true;
        }
    }
}

